-- Pilot RBAC seed — generated by scripts/generate-pilot-seeds.ts
-- Idempotent: safe to re-run after supabase db reset --local

BEGIN;

ON CONFLICT (name) DO UPDATE SET
  description = EXCLUDED.description,
  is_active = EXCLUDED.is_active,
  updated_at = now();

ON CONFLICT (module_name, action) DO UPDATE SET
  description = EXCLUDED.description;

-- ADMIN: full permission matrix
SELECT r.id, p.id
FROM public.sys_roles r
CROSS JOIN public.sys_permissions p
WHERE r.name = 'ADMIN'
ON CONFLICT (role_id, permission_id) DO NOTHING;

-- NHAN_VIEN_KSNK: operational subset (view/create/edit/delete/import on supervision + CSSD + core MDM views)
SELECT r.id, p.id
FROM public.sys_roles r
JOIN public.sys_permissions p ON true
WHERE r.name = 'NHAN_VIEN_KSNK'
  AND (
    (p.module_name IN ('GIAM_SAT_VST','GIAM_SAT_CHUNG','GIAM_SAT_NKBV','CONG_VIEC','BAO_SU_CO')
     AND p.action IN ('view','create','edit','delete','import'))
    OR (p.module_name LIKE 'DASHBOARD%' AND p.action IN ('view','export'))
    OR (p.module_name IN ('CSSD_WORKFLOW','CSSD_KHO_DUNGCU','CSSD_REPORT','CSSD_ME_TIET_KHUAN','KSNK_KHO_HOACHAT')
        AND p.action IN ('view','create','edit','delete','import','qc','lock','export'))
    OR (p.module_name IN ('NHAN_SU','BANG_KIEM','DANH_MUC') AND p.action IN ('view','create','edit','delete','import'))
    OR (p.module_name = 'PHAN_QUYEN' AND p.action = 'view')
    OR (p.module_name IN ('LOAI_DC','BO_DC','DC_LE','THIET_BI','HOA_CHAT','KHOA_PHONG','BANG_KIEM_DETAIL') AND p.action = 'view')
  )
ON CONFLICT (role_id, permission_id) DO NOTHING;

COMMIT;
